  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}
```

**Why correctness is preserved:** Same rounding, same sort direction (descending by `totalSpent`), same `slice(0, n)`. ✓

---

### Step 5 — `searchTransactions`: O(n²) → O(n)

**Problem:** A brand-new `RegExp` is compiled on every iteration; the dedup scan through `results` is O(r) per transaction.

**Fix:** Compile the `RegExp` once before the loop; replace the linear dedup scan with a `Set<string>` of seen IDs.

```typescript
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
  const seen = new Set<string>();
  const results: Transaction[] = [];

  for (const transaction of transactions) {
    if (pattern.test(transaction.description) && !seen.has(transaction.id)) {
      seen.add(transaction.id);
      results.push(transaction);
    }
  }

  return results;
}
```

**Why correctness is preserved:** Same regex escape logic, same `"i"` flag, same output order. Special-character test (`$5.00`) still works because the escape logic is unchanged. ✓

---

### Step 6 — `processAll`: no change needed

`processAll` simply delegates to `groupByCategory`, `findDuplicates`, and `topSpenders`. After the above optimizations, the combined pipeline (O(n) each) will comfortably fit within the 200ms budget for 20k records.

---

## Verification

Run the full test suite with:

```bash
