import {
  Transaction,
  CategoryGroup,
  DuplicateGroup,
  RunningBalanceEntry,
  SpenderSummary,
  PipelineResult,
} from "./types.js";

/**
 * Groups transactions by category and calculates totals.
 *
 * Optimized: uses a Map for O(1) category lookup and increments
 * the total directly instead of recalculating with reduce.
 * Overall complexity: O(n).
 */
export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
  const groupMap = new Map<string, CategoryGroup>();

  for (const transaction of transactions) {
    const existing = groupMap.get(transaction.category);
    if (existing) {
      existing.transactions.push(transaction);
      existing.total += transaction.amount;
    } else {
      groupMap.set(transaction.category, {
        category: transaction.category,
        transactions: [transaction],
        total: transaction.amount,
      });
    }
  }

  return Array.from(groupMap.values());
}

/**
 * Finds duplicate transactions (same userId + amount + date).
 *
 * Optimized: single pass using a Map keyed by "userId|amount|date".
 * Groups with only one entry are not duplicates and are filtered out.
 * Overall complexity: O(n).
 */
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const groupMap = new Map<string, DuplicateGroup>();

  for (const transaction of transactions) {
    const key = `${transaction.userId}|${transaction.amount}|${transaction.date}`;
    const existing = groupMap.get(key);
    if (existing) {
      existing.transactions.push(transaction);
    } else {
      groupMap.set(key, { key, transactions: [transaction] });
    }
  }

  return Array.from(groupMap.values()).filter(g => g.transactions.length > 1);
}

/**
 * Calculates running balance for a specific user, sorted by date.
 *
 * Optimized: filters user transactions once, sorts once, then does
 * a single accumulating pass to build entries.
 * Overall complexity: O(n + m log m) where m = user's transaction count.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  const userTransactions = transactions.filter(t => t.userId === userId);
  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  const entries: RunningBalanceEntry[] = [];
  let balance = 0;
  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}

/**
 * Returns the top N spenders.
 *
 * Optimized: single pass with a Map to accumulate totals and counts,
 * then a single Array.sort instead of bubble sort.
 * Overall complexity: O(n + u log u) where u = unique user count.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const userMap = new Map<string, { totalSpent: number; transactionCount: number }>();

  for (const t of transactions) {
    const existing = userMap.get(t.userId);
    if (existing) {
      existing.totalSpent += t.amount;
      existing.transactionCount++;
    } else {
      userMap.set(t.userId, { totalSpent: t.amount, transactionCount: 1 });
    }
  }

  const summaries: SpenderSummary[] = Array.from(userMap.entries()).map(
    ([userId, { totalSpent, transactionCount }]) => ({
      userId,
      totalSpent: Math.round(totalSpent * 100) / 100,
      transactionCount,
    })
  );

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 *
 * Optimized: compiles the RegExp once before the loop and uses a Set
 * for O(1) duplicate detection instead of a linear scan.
 * Overall complexity: O(n).
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
  const seen = new Set<string>();
  const results: Transaction[] = [];

  for (const transaction of transactions) {
    if (pattern.test(transaction.description) && !seen.has(transaction.id)) {
      seen.add(transaction.id);
      results.push(transaction);
    }
  }

  return results;
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

